mapper.select:
select cz.id,cz.name, cz.room, cz.begin_date,cz.end_date, e.name masterName, cz.subject, cz.create_time, cz.update_time, case when cz.end_date < now() then '已结课' when cz.begin_date > now() then '未开课' else '在读' end as status from clazz cz left join emp e on cz.master_id=e.id
and cz.name like concat('%',#{name},'%')
and end_date between #{begin} and #{end}

mapper.update:
update clazz
name=#{name}, room=#{room}, begin_date=#{beginDate}, end_date=#{endDate}, master_id=#{masterId}, subject=#{subject}, update_time=#{updateTime},
where id = #{id}
